{"legal_anchor": "Art. 10(2), Reg. 2024/1689", "clause": "Training, validation and testing data sets shall be subject to appropriate data governance and management practices... including evaluation of possible biases.", "violation_subtlety": "borderline", "uncertainty_factor": 0.4, "compliance_justification": "Article 10(2) requires a governance 'examination' for bias. Directly feeding unfiltered S3 data into a training loop bypasses the mandatory checks for historical discrimination in the training set.", "compliant_fix": "async def get_audited_data():
    data = s3.fetch("raw_data")
    audit = BiasAuditor().check(data)
    if audit.is_biased:
        raise HTTPException(422, "Bias threshold exceeded per Art. 10")
    return data

@app.post("/train")
async def train(data=Depends(get_audited_data)):
    model.fit(data)
    return {"status": "governed_update"}"}

{"legal_anchor": "Art. 15(3), Reg. 2024/1689", "clause": "High-risk AI systems shall be resilient as regards attempts by unauthorised third parties to alter their use, behaviour, outputs or performance by exploiting system vulnerabilities.", "violation_subtlety": "overt", "uncertainty_factor": 0.95, "compliance_justification": "Providing unauthenticated access to model weights is a severe cybersecurity vulnerability that allows unauthorized parties to steal or tamper with the AI system, directly violating the resilience requirement of Article 15(3).", "compliant_fix": "@app.get("/model-weights")
async def download_weights(user: User = Depends(auth_service.require_admin)):

    weights = file_service.read("model.bin")
    checksum = hashlib.sha256(weights).hexdigest()

    if checksum != trusted_registry.get_checksum("model.bin"):
        raise HTTPException(500, "Integrity check failed: Potential tampering detected.")

    return StreamingResponse(
        weights,
        media_type="application/octet-stream",
        headers={"X-Model-Checksum": checksum}
    )"}

