{"legal_anchor": "Art. 14(1), Reg. 2024/1689", "clause": "High-risk AI systems shall be designed and developed in such a way, including with appropriate human-machine interface tools, that they can be effectively overseen by natural persons during the period in which they are in use.", "violation_subtlety": "overt", "uncertainty_factor": 0.85, "compliance_justification": "A high-frequency stream without any interface to pause, review, or intervene denies the human the ability to exercise effective oversight during use, violating Article 14.", "compliant_fix": "@app.websocket("/ws/autonomous-trading")
async def trading_feed(websocket: WebSocket):
    await websocket.accept()
    oversight_signal = asyncio.Event()
    for trade in high_frequency_trading_engine.stream(oversight_signal):
