{"legal_anchor": "Art. 11, Reg. 2024/1689", "clause": "The technical documentation of a high-risk AI system shall be drawn up before the high-risk AI system is placed on the market or put into service and shall be kept up-to-date.", "violation_subtlety": "borderline", "uncertainty_factor": 0.45, "compliance_justification": "Deploying a model without enforcing the existence of, or linking to, corresponding up-to-date technical documentation violates the pre-market documentation requirement and its maintenance obligation.", "compliant_fix": "@app.post("/deploy")
async def deploy_model_version(version: str, doc_hash: str = Form(...)):

